package com.example.sso.controller;

import jakarta.servlet.http.HttpServletRequest;
import jakarta.servlet.http.HttpServletResponse;
import jakarta.servlet.http.HttpSession;
import org.springframework.security.core.Authentication;
import org.springframework.security.core.context.SecurityContextHolder;
import org.springframework.security.web.authentication.logout.SecurityContextLogoutHandler;
import org.springframework.stereotype.Controller;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.RequestMapping;

import java.io.IOException;
import java.net.MalformedURLException;
import java.net.URL;
import java.util.List;

@Controller
@RequestMapping("/sso")
public class LogoutController {

    private static final String DEFAULT_REDIRECT_URL = "/login?logout";

    private static final List<String> ALLOWED_REDIRECT_DOMAINS = List.of(
            "app1.example.com",
            "app2.example.com",
            "app3.example.com",
            "www.example.com",
            "example.com"
    );

    @GetMapping("/logout")
    public void logout(HttpServletRequest request, HttpServletResponse response) throws IOException {
        // Perform security context cleanup
        Authentication authentication = SecurityContextHolder.getContext().getAuthentication();
        if (authentication != null) {
            new SecurityContextLogoutHandler().logout(request, response, authentication);
        }

        // Invalidate the HTTP session
        HttpSession session = request.getSession(false);
        if (session != null) {
            session.invalidate();
        }

        // Clear the security context
        SecurityContextHolder.clearContext();

        // Validate and redirect to the 'next' parameter URL
        String nextUrl = request.getParameter("next");
        String redirectUrl = resolveRedirectUrl(nextUrl);

        response.sendRedirect(redirectUrl);
    }

    /**
     * Validates the redirect URL to prevent open redirect vulnerabilities.
     * Only allows redirects to whitelisted domains or relative paths.
     *
     * @param nextUrl the URL from the 'next' request parameter
     * @return a safe redirect URL
     */
    private String resolveRedirectUrl(String nextUrl) {
        if (nextUrl == null || nextUrl.isBlank()) {
            return DEFAULT_REDIRECT_URL;
        }

        // Trim whitespace
        nextUrl = nextUrl.trim();

        // Block URLs that use protocol-relative format or contain newlines (header injection)
        if (nextUrl.startsWith("//") || nextUrl.contains("\r") || nextUrl.contains("\n")) {
            return DEFAULT_REDIRECT_URL;
        }

        // Allow relative paths that start with /
        if (nextUrl.startsWith("/") && !nextUrl.startsWith("//")) {
            return nextUrl;
        }

        // For absolute URLs, validate against the allowed domains whitelist
        try {
            URL url = new URL(nextUrl);
            String protocol = url.getProtocol();
            String host = url.getHost().toLowerCase();

            // Only allow http and https protocols
            if (!"http".equals(protocol) && !"https".equals(protocol)) {
                return DEFAULT_REDIRECT_URL;
            }

            // Check if the host is in the allowed domains list
            if (ALLOWED_REDIRECT_DOMAINS.contains(host)) {
                return nextUrl;
            }

            // Check if it's a subdomain of an allowed domain
            for (String allowedDomain : ALLOWED_REDIRECT_DOMAINS) {
                if (host.endsWith("." + allowedDomain)) {
                    return nextUrl;
                }
            }

        } catch (MalformedURLException e) {
            // If the URL is malformed, fall back to default
            return DEFAULT_REDIRECT_URL;
        }

        // If none of the checks passed, use the default redirect
        return DEFAULT_REDIRECT_URL;
    }
}